  scwin.sSysAdminYn = $c.data.getMemInfo($p, "sysAdminYn");
  const codeOptions = [{
    grpCd: "OP190",
    compID: "acb_workGubun"
  }, {
    grpCd: "OP101",
    compID: "acb_cntrSizCd"
  }];
