//-------------------------------------------------------------------------
// UDC 로딩
//-------------------------------------------------------------------------
scwin.onUdcCompleted = async function () {
  let e = "";
  scwin.sUserId = $c.data.getMemInfo($p, "userId");
  scwin.sUserClsCd = $c.data.getMemInfo($p, "userClsCd");
  scwin.sClntNo = $c.data.getMemInfo($p, "clntNo");
  scwin.sClntNm = $c.data.getMemInfo($p, "clntNm");
  scwin.sLobranCd = $c.data.getMemInfo($p, "loUpperLobranCd") == null ? "" : $c.data.getMemInfo($p, "loUpperLobranCd");
  scwin.sSysAdminYn = $c.data.getMemInfo($p, "sysAdminYn");
  wrkStDt.setValue(scwin.strDate);
  wrkEndDt.setValue(scwin.strDate);

  // 점소 조회
  e = await $c.sbm.execute($p, sbm_joblevel);
  if (e.responseJSON.resultDataSet[0].Msg == "SUCC") {
    scwin.sbm_joblevel_submitdone(e);
  }
  e = await $c.sbm.execute($p, sbm_dcScKnd);
  if (e.responseJSON.resultDataSet[0].Msg == "SUCC") {
    scwin.sbm_dcScKnd_submitdone(e);
  }
  if (scwin.DELETE_AUTH == "") {
    $c.gus.cfDisableBtn($p, [btn_Del]);
  }
  if (scwin.CREATE_AUTH == "") {
    $c.gus.cfDisableBtn($p, [btn_Add]);
  }
  if (scwin.PRINT_AUTH == "") {
    $c.gus.cfDisableBtn($p, [btn_Dcsn, btn_DcsnChoice]);
  }
  // 작업구분 초기화
  acb_workGubun.setValue("C");
  scwin.f_createGrid();
  $c.gus.cfDisableObjects($p, [ed_dptStDt, ed_dptEndDt, udc_dptDt]);
};
scwin.ondataload = function () {};

//-------------------------------------------------------------------------
// Function
//-------------------------------------------------------------------------
scwin.f_createGrid = function () {
  if (ds_emp.getCellData(0, "wrkCls") == "C" || acb_workGubun.getValue() == "C") {
    if (acb_logisticsBranch.getValue() == "6AA") {
      gr_emp.show();
      gr_emp2.hide();
      gr_emp3.hide();
      udc_section1.setGridId("gr_emp");
    } else {
      gr_emp.hide();
      gr_emp2.show();
      gr_emp3.hide();
      udc_section1.setGridId("gr_emp2");
    }
  } else {
    gr_emp.hide();
    gr_emp2.hide();
    gr_emp3.show();
    udc_section1.setGridId("gr_emp3");
  }
};
