// 등록
scwin.f_Register = async function () {
  var activeGrid = scwin.f_getActiveGrid();
  var k = 0;
  if (ds_emp.getModifiedIndex().length == 0) {
    await $c.gus.cfAlertMsg($p, MSG_CM_WRN_001, ["Data"]);
    return;
  }
  if (scwin.CREATE_AUTH == "") {
    await $c.gus.cfAlertMsg($p, "등록 권한이 없습니다.");
    return;
  }
  if (ica_allCopCoConfirmDt.getValue() != "") {
    if (!$c.gus.cfValidate($p, [ica_allCopCoConfirmDt])) {
      return;
    }
  }
  for (var i = 0; i < ds_emp.getRowCount(); i++) {
    if (ds_emp.getCellData(i, "che") == 1) {
      k++;
      if (ds_emp.getCellData(i, "dcScNm") == "") {
        ds_emp.setRowPosition(i);
        if (await $c.gus.cfAlertMsg($p, i + 1 + "번째 등록이 되지 않았습니다. \n 할인할증사유를 먼저 선택 해주세요")) {
          activeGrid.setFocusedCell(i, "dcScNm", true);
          return;
        }
      }
      if (ica_allCopCoConfirmDt.getValue().trimAll() != "") {
        ds_emp.setCellData(i, "regDtm", ica_allCopCoConfirmDt.getValue());
        ds_emp.setCellData(i, "confirmDt", ica_allCopCoConfirmDt.getValue());
      }
    } else {
      ds_emp.undoRow(i);
    }
  }
  if (k == 0) {
    await $c.gus.cfAlertMsg($p, MSG_CM_ERR_056, ["항목"]);
    return;
  }

  // Grid의 필수 입력 항목에 대해서 Check 한다.
  if (!$c.gus.cfValidate($p, [activeGrid])) {
    return;
  }
  let regChk = await $c.win.confirm($p, MSG_CM_CRM_002);
  if (regChk) {
    scwin.f_HeaderCreate();
    $c.sbm.setAction($p, sbm_saveEmp, "/ds.op.wrkrslts.transwrkrslts.RegistSurchargeInformationCMD.do?pageGubun=1");
    let e = await $c.sbm.execute($p, sbm_saveEmp);
    if (e.responseJSON.resultDataSet[0].Msg == "SUCC") {
      scwin.sbm_saveEmp_submitdone(e);
    }
  }
};

// 확정
scwin.f_Dcsn = async function () {
  if (ds_emp.getModifiedIndex().length == 0) {
    await $c.gus.cfAlertMsg($p, MSG_CM_WRN_001, ["Data"]);
    return;
  }
  var activeGrid = scwin.f_getActiveGrid();
  // Grid의 필수 입력 항목에 대해서 Check 한다.
  if (!$c.gus.cfValidate($p, [activeGrid])) {
    return;
  }
  if (ica_allCopCoConfirmDt.getValue() != "") {
    if (!$c.gus.cfValidate($p, [ica_allCopCoConfirmDt])) {
      return;
    }
  }
  var j = 0;
  for (var i = 0; i < ds_emp.getRowCount(); i++) {
    if (ds_emp.getCellData(i, "che") == "1") {
      j++;
      if (ds_emp.getCellData(i, "dcsnDt") != "" && Number(ds_emp.getCellData(i, "regDtm")) > Number(ds_emp.getCellData(i, "dcsnDt"))) {
        ds_emp.setRowPosition(i);
        if (await $c.gus.cfAlertMsg($p, "확정일자는 등록일자보다 빠를수 없습니다.")) {
          activeGrid.setFocusedCell(i, "dcsnDt", true);
          return;
        }
      }
      if (ica_allCopCoConfirmDt.getValue().trimAll() != "") {
        ds_emp.setCellData(i, "regDtm", ica_allCopCoConfirmDt.getValue());
      }
    } else {
      ds_emp.undoRow(i);
    }
  }
  if (j == 0) {
    await $c.gus.cfAlertMsg($p, MSG_CM_ERR_056, ["Data"]);
    return;
  }
  let chk = await $c.win.confirm($p, "확정하시겠습니까");
  if (chk) {
    scwin.f_HeaderCreate();
    $c.sbm.setAction($p, sbm_saveEmp, "/ds.op.wrkrslts.transwrkrslts.RegistSurchargeDecisionCMD.do?pageGubun=1");
    let e = await $c.sbm.execute($p, sbm_saveEmp);
    if (e.responseJSON.resultDataSet[0].Msg == "SUCC") {
      scwin.sbm_saveEmp_submitdone(e);
    }
  }
};
