scwin.gr_emp_CustomFormatter = function (data, formattedData, rowIndex, colIndex) {
  let columnId = $c.util.getComponent($p, this.id).getColumnID(colIndex);
  let val = data,
    color = "black";
  if (columnId == "odrNo") {
    color = "blue";
  } else if (columnId == "arvDtm") {
    if (ds_emp.getCellData(rowIndex, "arvDtm") == "") {
      val = "";
    }
  } else if (columnId == "cntrNo") {
    if (ds_emp.getCellData(rowIndex, "cntrNo") == "") {
      val = "";
    }
    color = "blue";
  } else if (columnId == "cntrSizCd") {
    if (ds_emp.getCellData(rowIndex, "cntrSizCd") == "") {
      val = "";
    }
  } else if (columnId == "dcScTotal") {
    if (ds_emp.getCellData(rowIndex, "dcScAmt") == 0) {
      val = ds_emp.getCellData(rowIndex, "pchsAmt");
    } else {
      val = Number(ds_emp.getCellData(rowIndex, "pchsAmt")) + Number(ds_emp.getCellData(rowIndex, "dcScAmt"));
    }
    val = val.toString().replace(/\B(?=(\d{3})+(?!\d))/g, ",");
  }
  gr_emp.setCellColor(rowIndex, colIndex, color);
  return val;
};
