scwin.gr_emp_oncellclick = async function (rowIndex, columnIndex, columnId) {
  var t = 0;
  var p = 0;
  var cur = 0;
  if (columnId == "commNm") {
    if (ds_emp.getCellData(ds_emp.getRowPosition(), "commNm") != "") {
      // 운송할인할증(건별)
      if (ds_emp.getRowCount() < 1) {
        await $c.gus.cfAlertMsg($p, MSG_CM_WRN_002, [""]);
        return;
      }
      var transWrkIndictNo = ds_emp.getCellData(rowIndex, "transWrkIndictNo");
      var param = {
        transWrkIndictNo: transWrkIndictNo,
        lobranCd: acb_logisticsBranch.getValue(),
        wrkStDt: wrkStDt.getValue(),
        wrkCls: 'B'
      };
      $c.win.openMenu($p, "운송할인할증등록", "/ui/ds/op/wrkrslts/transwrkrslts/op_304_03_01b.xml", "op_304_03_01b.xml", param, {
        openAction: "exist"
      });
    } else if (ds_emp.getCellData(ds_emp.getRowPosition(), "commNm") == "") {
      await $c.gus.cfAlertMsg($p, "품명이 있는 항목을 선택하세요");
      return;
    }
  } else if (columnId == "cntrNo") {
    // 운송할인할증(건별)
    if (ds_emp.getCellData(ds_emp.getRowPosition(), "cntrNo") != "") {
      // 
      if (ds_emp.getRowCount() < 1) {
        await $c.gus.cfAlertMsg($p, MSG_CM_WRN_002, [""]);
        return;
      }
      var transWrkIndictNo = ds_emp.getCellData(rowIndex, "transWrkIndictNo");
      var cntrNo = ds_emp.getCellData(ds_emp.getRowPosition(), "cntrNo");
      var param = {
        transWrkIndictNo: transWrkIndictNo,
        lobranCd: acb_logisticsBranch.getValue(),
        wrkStDt: wrkStDt.getValue(),
        wrkCls: 'C',
        cntrNo: cntrNo
      };
      $c.win.openMenu($p, "운송할인할증(건별)", "/ui/ds/op/wrkrslts/transwrkrslts/op_304_03_01b.xml", "op_304_03_01b.xml", param, {
        openAction: "exist"
      });
    } else if (ds_emp.getCellData(ds_emp.getRowPosition(), "commNm") == "") {
      await $c.gus.cfAlertMsg($p, "품명이 있는 항목을 선택하세요");
      return;
    }
  } else if (columnId == "dcScNm") {
    // 할인할증사유
    if (btn_Add.getStyle("display") == "none") {
      if (await $c.gus.cfAlertMsg($p, "등록 권한이 없습니다.")) {
        //     gr_emp3.setColumnProperty("dcScNm", "edit", "none"); 
        gr_emp.setCellDisableEdit(ds_emp.getRowPosition(), "dcScNm", "none");
        return;
      }
    }
    for (var i = 0; i < ds_emp.getRowCount(); i++) {
      if (ds_emp.getCellData(i, "transWrkIndictNo") == ds_emp.getCellData(rowIndex, "transWrkIndictNo") && ds_emp.getCellData(i, "transRsltsSeq") == ds_emp.getCellData(rowIndex, "transRsltsSeq")) {
        t++;
        p = i;
      }
    }
    cur = p - t + 1;
    if (cur != rowIndex) {
      if (await $c.gus.cfAlertMsg($p, "추가된 항목이므로 더 이상 추가할 수 없습니다.")) {
        //      gr_emp3.setColumnProperty("dcScNm", "edit", "none");  
        gr_emp.setCellDisableEdit(ds_emp.getRowPosition(), "dcScNm", "none");
        return;
      }
    } else {
      gr_emp.setColumnProperty("dcScNm", "edit", "Any");
    }
  } else if (columnId == "dcsnYn") {
    if (btn_Del.getStyle("display") == "none") {
      if (await $c.gus.cfAlertMsg($p, "확인 권한이 없습니다.")) {
        //    gr_emp3.setColumnProperty("dcsnYn", "edit", "none"); 
        gr_emp.setCellDisableEdit(ds_emp.getRowPosition(), "dcsnYn", "none");
        return;
      }
    }
  } else if (columnId == "odrNo") {
    var odrNo = ds_emp.getCellData(rowIndex, "odrNo");
    var param = {
      odrNo,
      paramOdrNo: odrNo
    };
    $c.win.openMenu($p, "오더완료처리", "/ui/ds/op/wrkrslts/transwrkrslts/op_304_01_04b.xml", "op_304_01_04b.xml", param, {
      openAction: "exist"
    });
  }
};
